SET NOCOUNT ON;

INSERT INTO system_edt_mappings (
  element_name, element_mssql_type, element_postgresql_type, element_mysql_type,
  element_python_type, element_odbc_type_code, element_max_length, element_notes
) VALUES
  ('INT32', 'int', 'integer', 'int', 'int', 4, 4, 'Standard 32-bit signed integer.'),
  ('INT64', 'bigint', 'bigint', 'bigint', 'int', -5, 8, 'Standard 64-bit signed integer.'),
  ('INT64_IDENTITY', 'bigint identity(1,1)', 'bigserial', 'bigint auto_increment', 'int', -5, 8, 'Auto-numbering key: MSSQL IDENTITY, PostgreSQL BIGSERIAL, MySQL AUTO_INCREMENT.'),
  ('UUID', 'uniqueidentifier', 'uuid', 'char(36)', 'UUID', -11, 36, 'Prefer native UUID in MSSQL/PostgreSQL; MySQL uses char(36) or BINARY(16).'),
  ('BOOL', 'bit', 'boolean', 'boolean', 'bool', -7, 1, 'MSSQL BIT stores 0/1; PostgreSQL and MySQL BOOLEAN are logical aliases.'),
  ('DATETIME_TZ', 'datetimeoffset(7)', 'timestamptz', 'timestamp', 'datetime', -150, NULL, 'Timezone-aware moment. ODBC type -150 requires explicit handling.'),
  ('STRING', 'nvarchar', 'varchar', 'varchar', 'str', -9, NULL, 'Bounded Unicode string. Use element_max_length for column limits.'),
  ('TEXT', 'nvarchar(max)', 'text', 'longtext', 'str', -10, NULL, 'Large/unbounded text payload.'),
  ('INT8', 'tinyint', 'smallint', 'tinyint', 'int', -6, 1, 'Unsigned 8-bit integer (0-255). PostgreSQL uses smallint as nearest equivalent.'),
  ('DATE', 'date', 'date', 'date', 'date', 91, NULL, 'Calendar date without time or timezone. Used for period boundaries and calendar definitions where timezone is not meaningful.'),
  ('DECIMAL_19_5', 'decimal(19,5)', 'numeric(19,5)', 'decimal(19,5)', 'Decimal', 3, 19, 'Fixed-point financial amount. 19 digits total, 5 after decimal. Stored and computed at 5dp, quantized to 4dp before posting per precision policy.'),
  ('DECIMAL_28_12', 'decimal(28,12)', 'numeric(28,12)', 'decimal(28,12)', 'Decimal', 3, 28, 'High-precision staging decimal. 28 digits total, 12 after decimal. Used in staging tables to preserve full provider precision before GL quantization.');

